fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 10_i64.pow(9) + 7;

    for query in queries {
        let [li, ri, ki, vi] = query;
        let mut idx = li;
        while idx <= ri {
            nums[idx as usize] = (nums[idx as usize] * vi) % MOD;
            idx += ki;
        }
    }

    let mut xor_result = 0_i64;
    for &num in &nums {
        xor_result ^= num;
    }

    xor_result
}
